import sys

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    a = list(map(int, input_data[1:n+1]))

    # dp[x] = minimum last element of an increasing subsequence with XOR value x
    # Initialize with empty subsequence: XOR=0, last=-1
    INF = float('inf')
    MAX_XOR = 512

    dp = [INF] * MAX_XOR
    dp[0] = -1  # empty subsequence

    for num in a:
        # We need to process updates: for each x where dp[x] < num,
        # we can update dp[x ^ num] = min(dp[x ^ num], num)
        # We must use the OLD dp values to avoid using num twice in same step
        new_updates = {}
        for x in range(MAX_XOR):
            if dp[x] < num:
                new_x = x ^ num
                if num < dp[new_x]:  # num would be the new last element
                    if new_x not in new_updates or num < new_updates[new_x]:
                        new_updates[new_x] = num

        for x, val in new_updates.items():
            if val < dp[x]:
                dp[x] = val

    result = []
    for x in range(MAX_XOR):
        if dp[x] != INF:
            result.append(x)

    print(len(result))
    print(' '.join(map(str, result)))

solve()

